// src/pages/RegisterManageSub2Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../Dashboard.css';
import './RegisterManageSub2Page.css'; // Import file CSS mới cho trang này

function FarmListPage() {
  // State to store the list of breeding facilities
  const [farms, setFarms] = useState([]);
  // State for general search filter
  const [filter, setFilter] = useState('');
  // State for Province (City) filter
  const [selectedProvince, setSelectedProvince] = useState('');
  // State for Commune (Ward) filter
  const [selectedCommune, setSelectedCommune] = useState('');
  // State for Species filter
  const [selectedSpecies, setSelectedSpecies] = useState('');
  // New state for Registration Facility Type filter (Breeding / Wood Business)
  const [selectedLoaiCoSoDangKy, setSelectedLoaiCoSoDangKy] = useState('');
  // New state for Wood Business Industry filter
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  // New state for Status filter
  const [selectedTrangThai, setSelectedTrangThai] = useState(''); // Thêm state cho lọc Trạng thái

  // State to store unique Province (City) values for dropdown
  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  // State to store unique Commune (Ward) values for dropdown
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  // State to store unique Species values for dropdown
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  // State to store unique Registration Facility Type values for dropdown
  const [uniqueLoaiCoSoDangKy, setUniqueLoaiCoSoDangKy] = useState([]);
  // State to store unique Wood Business Industry values for dropdown
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);
  // State to store unique Status values for dropdown
  const [uniqueTrangThai, setUniqueTrangThai] = useState([]); // Thêm state cho unique Trạng thái

  // Hook for page navigation
  const navigate = useNavigate();
  // Get authentication token from localStorage
  const token = localStorage.getItem('token');

  // Define table columns and their initial visibility state
  const initialColumnsConfig = {
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '120px' },
    tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
    xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '150px' },
    vido: { id: 'vido', label: 'Vĩ độ', visible: true, minWidth: '80px' },
    kinhdo: { id: 'kinhdo', label: 'Kinh độ', visible: true, minWidth: '80px' },
    ghiChu: { id: 'ghiChu', label: 'Ghi chú', visible: false, minWidth: '150px' },
    tenNguoiDaiDien: { id: 'tenNguoiDaiDien', label: 'Người đại diện', visible: true, minWidth: '120px' },
    soDienThoaiNguoiDaiDien: { id: 'soDienThoaiNguoiDaiDien', label: 'SĐT Người đại diện', visible: true, minWidth: '100px' },
    emailNguoiDaiDien: { id: 'emailNguoiDaiDien', label: 'Email Người đại diện', visible: true, minWidth: '150px' },
    loaiHinhCoSo: { id: 'loaiHinhCoSo', label: 'Loại hình cơ sở', visible: true, minWidth: '120px' },
    ngayThanhLap: { id: 'ngayThanhLap', label: 'Ngày thành lập', visible: true, minWidth: '100px' },
    giayPhepKinhDoanh: { id: 'giayPhepKinhDoanh', label: 'Số GPKD', visible: true, minWidth: '100px' },
    mucDichNuoi: { id: 'mucDichNuoi', label: 'Mục đích nuôi', visible: false, minWidth: '120px' },
    hinhThucNuoi: { id: 'hinhThucNuoi', label: 'Hình thức nuôi', visible: false, minWidth: '120px' },
    maSoCoSoGayNuoi: { id: 'maSoCoSoGayNuoi', label: 'Mã số CS gây nuôi', visible: false, minWidth: '120px' },
    tongDan: { id: 'tongDan', label: 'Tổng đàn', visible: true, minWidth: '80px' },
    loaiHinhKinhDoanhGo: { id: 'loaiHinhKinhDoanhGo', label: 'Loại hình KD gỗ', visible: false, minWidth: '120px' },
    nganhNgheKinhDoanhGo: { id: 'nganhNgheKinhDoanhGo', label: 'Ngành nghề KD gỗ', visible: false, minWidth: '120px' },
    khoiLuong: { id: 'khoiLuong', label: 'Khối lượng', visible: true, minWidth: '80px' },
    tenLamSan: { id: 'tenLamSan', label: 'Tên lâm sản', visible: true, minWidth: '120px' },
    tenKhoaHoc: { id: 'tenKhoaHoc', label: 'Tên khoa học', visible: true, minWidth: '150px' },
    trangThai: { id: 'trangThai', label: 'Trạng thái', visible: true, minWidth: '100px' },
    loaiCoSoDangKy: { id: 'loaiCoSoDangKy', label: 'Loại CS Đăng ký', visible: true, minWidth: '150px' },
    licenseNumber: { id: 'licenseNumber', label: 'Số giấy phép', visible: false, minWidth: '100px' },
    issueDate: { id: 'issueDate', label: 'Ngày cấp GP', visible: false, minWidth: '100px' },
    expiryDate: { id: 'expiryDate', label: 'Ngày hết hạn GP', visible: false, minWidth: '100px' },
    actions: { id: 'actions', label: '🛠️', visible: true, width: '70px', minWidth: '70px', maxWidth: '70px' }, // Action column fixed width
  };

  // State to manage column visibility
  const [columns, setColumns] = useState(initialColumnsConfig);
  // State to manage visibility of the column options panel
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  // Pagination states
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15); // Default 15 items per page

  // useEffect to load column visibility from localStorage on component mount
  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility');
      if (savedColumns) {
        const parsedSavedColumns = JSON.parse(savedColumns);
        const mergedColumns = Object.keys(initialColumnsConfig).reduce((acc, key) => {
          const savedCol = parsedSavedColumns.find(sCol => sCol.id === key);
          // Merge saved visibility, ensuring initial config properties (like width) are retained
          acc[key] = savedCol ? { ...initialColumnsConfig[key], visible: savedCol.visible } : initialColumnsConfig[key];
          return acc;
        }, {});
        setColumns(mergedColumns);
      }
    } catch (error) {
      console.error("Error loading column visibility from localStorage:", error);
      // Fallback to initial columns if loading fails
      setColumns(initialColumnsConfig);
    }
  }, []); // Empty dependency array means this runs once on mount

  // useEffect to save column visibility to localStorage whenever columns state changes
  useEffect(() => {
    try {
      // Only save id and visible to avoid storing unnecessary CSS properties
      const columnsToSave = Object.keys(columns).map(key => ({
        id: key,
        visible: columns[key].visible
      }));
      localStorage.setItem('tableColumnsVisibility', JSON.stringify(columnsToSave));
    } catch (error) {
      console.error("Error saving column visibility to localStorage:", error);
    }
  }, [columns]); // Runs whenever 'columns' state changes


  // useEffect to fetch farm list when component mounts or when selectedLoaiCoSoDangKy changes
  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const params = {};
        // Add farmType filter to params if selectedLoaiCoSoDangKy is chosen
        if (selectedLoaiCoSoDangKy !== '') {
          params.farmType = selectedLoaiCoSoDangKy;
        }
        // Thêm trạng thái vào params nếu được chọn
        if (selectedTrangThai !== '') {
          params.trangThai = selectedTrangThai;
        }

        // Send GET request to API to get farm list
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}` // Send authentication token in header
          },
          params: params // Pass filter parameters to backend
        });
        setFarms(response.data); // Update farms state with received data

        // Extract unique values for filters from loaded data
        const provinces = [...new Set(response.data.map(f => f.tinhThanhPho).filter(Boolean))].sort();
        const communes = [...new Set(response.data.map(f => f.xaPhuong).filter(Boolean))].sort();
        const species = [...new Set(response.data.flatMap(f => f.species ? f.species.map(s => s.name) : []).filter(Boolean))].sort();
        const loaiCoSoDangKy = [...new Set(response.data.map(f => f.loaiCoSoDangKy).filter(Boolean))].sort();
        const nganhNgheKinhDoanhGo = [...new Set(response.data.map(f => f.nganhNgheKinhDoanhGo).filter(Boolean))].sort();
        const trangThai = [...new Set(response.data.map(f => f.trangThai).filter(Boolean))].sort(); // Lấy unique trạng thái

        // Update states containing unique values
        setUniqueProvinces(provinces);
        setUniqueCommunes(communes);
        setUniqueSpecies(species);
        setUniqueLoaiCoSoDangKy(loaiCoSoDangKy);
        setUniqueNganhNgheKinhDoanhGo(nganhNgheKinhDoanhGo);
        setUniqueTrangThai(trangThai); // Cập nhật unique trạng thái

      } catch (error) {
        console.error('❌ Error fetching farm list:', error);
        // If error due to authentication (401) or unauthorized (403), redirect to login page
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
      }
    };

    // Only fetch data if token exists
    if (token) {
      fetchFarms();
    } else {
      navigate('/'); // Redirect if no token
    }
  }, [token, navigate, selectedLoaiCoSoDangKy, selectedTrangThai]); // Re-fetch when token, navigate or selectedLoaiCoSoDangKy or selectedTrangThai changes

  // Function to handle deleting a farm
  const handleDelete = async (id) => {
    // Replaced window.confirm with a custom modal if you have one
    // if (window.confirm('Are you sure you want to delete?')) {
      try {
        // Send DELETE request to API to delete farm
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        // Update farm list by filtering out the deleted farm
        setFarms(farms.filter(f => f._id !== id));
      } catch (error) {
        console.error('Error deleting:', error);
      }
    // }
  };

  // Function to handle editing a farm
  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Redirect to edit page with farm ID
  };

  // Function to handle viewing farm details
  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Redirect to details page with farm ID
  };

  // Filter farm list based on all criteria (frontend filtering for other fields)
  const filteredFarms = farms.filter(f => {
    // Check for general search filter match
    const generalMatch = (
      (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.ghiChu || '').toLowerCase().includes(filter.toLowerCase()) || // Include ghiChu in general search
      (f.loaiCoSoDangKy || '').toLowerCase().includes(filter.toLowerCase()) || // Include loaiCoSoDangKy in general search
      (f.nganhNgheKinhDoanhGo || '').toLowerCase().includes(filter.toLowerCase()) || // Include nganhNgheKinhDoanhGo in general search
      (f.tongDan && String(f.tongDan).toLowerCase().includes(filter.toLowerCase())) || // Include tongDan in general search
      (f.khoiLuong && String(f.khoiLuong).toLowerCase().includes(filter.toLowerCase())) || // Include khoiLuong in general search
      (f.tenLamSan && String(f.tenLamSan).toLowerCase().includes(filter.toLowerCase())) || // Include tenLamSan in general search
      (f.tenKhoaHoc && String(f.tenKhoaHoc).toLowerCase().includes(filter.toLowerCase())) || // Include tenKhoaHoc in general search
      (f.trangThai && String(f.trangThai).toLowerCase().includes(filter.toLowerCase())) // Include trangThai in general search
    );

    // Check for Province (City) filter match
    const provinceMatch = selectedProvince ? (f.tinhThanhPho === selectedProvince) : true;
    // Check for Commune (Ward) filter match
    const communeMatch = selectedCommune ? (f.xaPhuong === selectedCommune) : true;
    // Check for Species filter match
    const speciesMatch = selectedSpecies ? (f.species && f.species.some(s => s.name === selectedSpecies)) : true;
    // loaiCoSoDangKyMatch is now handled by backend filter, but kept for consistency if needed for other filters
    const nganhNgheKinhDoanhGoMatch = selectedNganhNgheKinhDoanhGo ? (f.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo) : true;
    // trangThaiMatch is now handled by backend filter, but kept for consistency if needed for other filters
    const trangThaiMatch = selectedTrangThai ? (f.trangThai === selectedTrangThai) : true;


    // Return true if all filter conditions match
    return generalMatch && provinceMatch && communeMatch && speciesMatch && nganhNgheKinhDoanhGoMatch && trangThaiMatch;
  });

  // Pagination logic
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredFarms.slice(indexOfFirstItem, indexOfLastItem);

  const totalPages = Math.ceil(filteredFarms.length / itemsPerPage);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  const nextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage(currentPage + 1);
    }
  };

  const prevPage = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    }
  };

  // Function to handle toggling column visibility
  const handleColumnToggle = (columnKey) => {
    setColumns(prevColumns => ({
      ...prevColumns,
      [columnKey]: {
        ...prevColumns[columnKey],
        visible: !prevColumns[columnKey].visible // Invert column visibility state
      }
    }));
  };

  // REMOVED: flexibleColumnWidth calculation as we will rely on minWidth for scrolling
  // const visibleNonActionColumnsCount = Object.keys(columns).filter(
  //   (key) => columns[key].visible && key !== 'actions'
  // ).length;
  // const flexibleColumnWidth = visibleNonActionColumnsCount > 0
  //   ? `calc((100% - ${initialColumnsConfig.actions.width}) / ${visibleNonActionColumnsCount})`
  //   : '0px'; // If no non-action columns are visible, their width is 0.


  return (
    <div className="farm-list-container"> {/* Main container of the list page */}
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <div className="filter-container"> {/* Container for filters */}
        <input
          type="text"
          placeholder="🔍 Tìm kiếm chung..."
          value={filter}
          onChange={e => setFilter(e.target.value)}
        />

        {/* New filter for Registration Facility Type */}
        <select
          value={selectedLoaiCoSoDangKy}
          onChange={e => setSelectedLoaiCoSoDangKy(e.target.value)}
        >
          <option value="">Tất cả cơ sở</option>
          <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
          <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
        </select>

        <select
          value={selectedProvince}
          onChange={e => setSelectedProvince(e.target.value)}
        >
          <option value="">Tất cả Tỉnh (TP)</option>
          {uniqueProvinces.map(province => (
            <option key={province} value={province}>{province}</option>
          ))}
        </select>

        <select
          value={selectedCommune}
          onChange={e => setSelectedCommune(e.target.value)}
        >
          <option value="">Tất cả Xã (Phường)</option>
          {uniqueCommunes.map(commune => (
            <option key={commune} value={commune}>{commune}</option>
          ))}
        </select>

        <select
          value={selectedSpecies}
          onChange={e => setSelectedSpecies(e.target.value)}
        >
          <option value="">Tất cả Loài nuôi</option>
          {uniqueSpecies.map(species => (
            <option key={species} value={species}>{species}</option>
          ))}
        </select>

        {/* New filter for Wood Business Industry */}
        <select
          value={selectedNganhNgheKinhDoanhGo}
          onChange={e => setSelectedNganhNgheKinhDoanhGo(e.target.value)}
        >
          <option value="">Tất cả Ngành nghề KD gỗ</option>
          {uniqueNganhNgheKinhDoanhGo.map(nganhNghe => (
            <option key={nganhNghe} value={nganhNghe}>{nganhNghe}</option>
          ))}
        </select>

        {/* New filter for Status */}
        <select
          value={selectedTrangThai}
          onChange={e => setSelectedTrangThai(e.target.value)}
        >
          <option value="">Tất cả Trạng thái</option>
          {uniqueTrangThai.map(status => (
            <option key={status} value={status}>{status}</option>
          ))}
          {/* Thêm các tùy chọn cố định nếu bạn muốn, ví dụ: */}
          {/* <option value="Hoạt động">Hoạt động</option>
          <option value="Tạm ngưng">Tạm ngưng</option>
          <option value="Nghỉ nuôi">Nghỉ nuôi</option> */}
        </select>

        <button
          onClick={() => setShowColumnOptions(!showColumnOptions)}
        >
          {/* Changed button text here */}
          {showColumnOptions ? 'Ẩn cột' : 'Hiện, ẩn cột'}
        </button>
      </div>

      {showColumnOptions && (
        <div className="column-options-container"> {/* Container for column options */}
          <h3>Chọn cột hiển thị:</h3>
          <div className="column-options-grid"> {/* Grid to display column options */}
            {Object.keys(columns).map(key => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  onChange={() => handleColumnToggle(key)}
                />
                {columns[key].label}
              </label>
            ))}
          </div>
        </div>
      )}

      {/* Display message when no farms are registered */}
      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {/* Table to display farm list if data exists */}
      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse">
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              {Object.keys(columns).map(key => (
                <th
                  key={key}
                  className={!columns[key].visible ? 'column-hidden' : ''}
                  style={
                    key === 'actions'
                      ? { // Action column: fixed width
                          width: initialColumnsConfig.actions.width,
                          minWidth: initialColumnsConfig.actions.minWidth,
                          maxWidth: initialColumnsConfig.actions.maxWidth,
                        }
                      : (columns[key].visible
                          ? { // Visible non-action columns: use minWidth from config for natural sizing
                              minWidth: columns[key].minWidth, // Use minWidth for column to push table width
                              width: columns[key].minWidth, // Set initial width to minWidth
                              maxWidth: 'auto', // Allow expanding
                            }
                          : {} // Hidden columns: let CSS class 'column-hidden' handle with display: none
                        )
                  }
                >
                  {columns[key].label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {currentItems.map((f, i) => ( // Use currentItems for pagination
              <tr key={f._id || i}>
                {Object.keys(columns).map(key => (
                  <td
                    key={`${f._id || i}-${key}`}
                    className={!columns[key].visible ? 'column-hidden' : ''}
                    style={
                      key === 'actions'
                        ? { // Action column: fixed width
                            width: initialColumnsConfig.actions.width,
                            minWidth: initialColumnsConfig.actions.minWidth,
                            maxWidth: initialColumnsConfig.actions.maxWidth,
                          }
                        : (columns[key].visible
                            ? { // Visible non-action columns: use minWidth from config for natural sizing
                                minWidth: columns[key].minWidth, // Use minWidth for column to push table width
                                width: columns[key].minWidth, // Set initial width to minWidth
                                maxWidth: 'auto', // Allow expanding
                              }
                            : {} // Hidden columns: let CSS class 'column-hidden' handle with display: none
                          )
                    }
                  >
                    {/* Handle date formatting for date fields */}
                    {['ngayThanhLap', 'ngayCapCCCD', 'issueDate', 'expiryDate'].includes(key) ?
                      (f[key] ? new Date(f[key]).toLocaleDateString() : '') :
                      (key === 'actions' ? (
                        <div className="action-buttons-cell"> {/* Cell containing action buttons */}
                          <button onClick={() => handleView(f._id)} className="action-button view-button">Sổ nuôi</button>{' '}
                          <button onClick={() => handleEdit(f._id)} className="action-button edit-button">✏️</button>{' '}
                          <button onClick={() => handleDelete(f._id)} className="action-button delete-button">🗑️</button>
                        </div>
                      ) : f[key])
                    }
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Pagination Controls */}
      {filteredFarms.length > 0 && (
        <div className="pagination-container">
          <div className="pagination-info">
            {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, filteredFarms.length)} / {filteredFarms.length} bản ghi
          </div>
          <div className="pagination-controls">
            <button onClick={prevPage} disabled={currentPage === 1} className="pagination-button">«</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button
                key={i + 1}
                onClick={() => paginate(i + 1)}
                className={`pagination-button ${currentPage === i + 1 ? 'active' : ''}`}
              >
                {i + 1}
              </button>
            ))}
            <button onClick={nextPage} disabled={currentPage === totalPages} className="pagination-button">»</button>
          </div>
          <div className="items-per-page">
            <select value={itemsPerPage} onChange={(e) => {
              setItemsPerPage(Number(e.target.value));
              setCurrentPage(1); // Reset to first page when items per page changes
            }}>
              <option value="5">5 bản ghi/trang</option>
              <option value="10">10 bản ghi/trang</option>
              <option value="20">20 bản ghi/trang</option>
              <option value="50">50 bản ghi/trang</option>
            </select>
          </div>
        </div>
      )}
    </div>
  );
}

export default FarmListPage;
